export function detectPlatformFromUrl(url: string): Platform | null {
  for (const [id, regex] of Object.entries(PLATFORM_PATTERNS)) {
    if (regex.test(url)) {
      return ALL_PLATFORMS.find(p => p.id === id) || null;
    }
  }
  return null;
}

export function getWatermarkFreePlatforms(): VideoPlatform[] {
  return VIDEO_PLATFORMS.filter(p => p.supportsWatermarkFree);
}

export function getPopularVideoPlatforms(): VideoPlatform[] {
  return VIDEO_PLATFORMS.filter(p => p.popular);
}

export function getPopularAudioPlatforms(): AudioPlatform[] {
  return AUDIO_PLATFORMS.filter(p => p.popular);
}

export function getPlatformsByRegion(region: string): Platform[] {
  return ALL_PLATFORMS.filter(p => p.region === region);
}

export function getVideoPlatformsByRegion(region: string): VideoPlatform[] {
  return VIDEO_PLATFORMS.filter(p => p.region === region);
}
